sql.where:


    AND id = #{id, jdbcType=BIGINT}


    AND id IN

        #{item, jdbcType=BIGINT}





        AND create_time >= #{createTime[0], jdbcType=TIMESTAMP}


        AND create_time <= #{createTime[1], jdbcType=TIMESTAMP}


        AND create_time BETWEEN #{createTime[0], jdbcType=TIMESTAMP}
        AND #{createTime[1], jdbcType=TIMESTAMP}




        AND update_time >= #{updateTime[0], jdbcType=TIMESTAMP}


        AND update_time <= #{updateTime[1], jdbcType=TIMESTAMP}


        AND update_time BETWEEN #{updateTime[0], jdbcType=TIMESTAMP}
        AND #{updateTime[1], jdbcType=TIMESTAMP}




    AND organ_id = #{organId, jdbcType=BIGINT}


    AND application_name = #{applicationName, jdbcType=VARCHAR}


    AND application_code = #{applicationCode, jdbcType=VARCHAR}


    AND can_integrate = #{canIntegrate, jdbcType=TINYINT}


    AND landing = #{landing, jdbcType=TINYINT}


    AND api_key_supported = #{apiKeySupported, jdbcType=TINYINT}


    AND application_type = #{applicationType, jdbcType=VARCHAR}


    AND application_type IN

        #{item, jdbcType=BIGINT}



    AND access_token_expires_in = #{accessTokenExpiresIn, jdbcType=INTEGER}


    AND refresh_token_expires_in = #{refreshTokenExpiresIn, jdbcType=INTEGER}


    AND endpoint_url = #{endpointUrl, jdbcType=VARCHAR}


    AND context_path = #{contextPath, jdbcType=VARCHAR}


    AND status = #{status, jdbcType=VARCHAR}


    AND description = #{description, jdbcType=VARCHAR}


AND (delete_flag = 0 OR delete_flag IS NULL)
